$requestedFile = $_GET['file'];

// Sanitize the requested filename to prevent directory traversal attacks
// Remove any '..' components and ensure it doesn't start with '/' or '\'
$requestedFile = str_replace(['../', '..\\'], '', $requestedFile);
$requestedFile = ltrim($requestedFile, '/\\');

